var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"여긴… 함선 내부가 아니잖아?","JPN":"ここは……艦船の中じゃないね？","ENG":"This... isn't the inside of the ship.","TWN":"這裡……並不是艦船內部？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"방금 들어온 입구도 사라졌어.","JPN":"今入ってきた入口も消えた。","ENG":"Even the entrance I just came through is gone.","TWN":"剛剛走進來的入口也不見了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"처음 와보는 장소인데, 어째 익숙한 느낌이네.","JPN":"初めてくる場所なのに、知っているような気がする。","ENG":"It's somewhere I've never been, but it feels familiar.","TWN":"之前明明從沒來過這個地方，但不知為何感覺很熟悉。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"응…?","JPN":"あれ……？","ENG":"Hmm...?","TWN":"嗯……？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_QM","text":{"KOREA":"적응이 빠르네. 주변 사람들이 전부 사라졌는데 당황하지도 않고.","JPN":"適応が早いね。周りの人が全員居なくなったのに慌てたりもしないし。","ENG":"You adapt fast. You didn't even panic when your friends went missing.","TWN":"你適應得很快。身邊的人都消失了也這麼冷靜。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"양자 터널이라고 했던가?","JPN":"量子トンネルと言ったっけ？","ENG":"Quantum tunnel, was it?","TWN":"似乎叫量子通道？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"예전에 리플레이서를 상대할 때도 비슷한 경험을 한 적이 있거든.","JPN":"以前リプレイサーの相手をしたときも、似たような経験をしたからね。","ENG":"I had a similar experience when fighting Replacers a while back.","TWN":"我過去在對付克隆集團時也有過類似經歷。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"네 정체는 이미 알고 있어, 도플갱어.","JPN":"あなたの正体は既にわかっている、ドッペルゲンガー。","ENG":"So I already know what you are, doppelganger.","TWN":"我已經知道你是誰了，二重身。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그림자 전당에 득시글대는, 진짜를 흉내내는 가짜지.","JPN":"影の殿堂にうじゃうじゃいる、本物を真似する偽物。","ENG":"You're a fake, imitating real people, crawling around in the Shadow Palace.","TWN":"你是只會模仿真品的贗品，暗影殿堂佈滿了你這樣的傢伙。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_QM","text":{"KOREA":"정말로 그렇게 생각해?","JPN":"本当にそう思う？","ENG":"Do you really think so?","TWN":"你真的這麼認為嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_QM","text":{"KOREA":"그럼 도플갱어가 이런 것도 흉내 낼 수 있을까?","JPN":"じゃあ、ドッペルゲンガーがこんなことも真似できると思う？","ENG":"Then, do you think a doppelganger can mimic these things too?","TWN":"那麼，二重身也能模仿這個嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"큭?! 울브즈베인…? 그걸 똑같이 복제할 수 있다고?","JPN":"くっ！？　ウルブズベイン……？　あれをそっくりコピーできると？","ENG":"Kgh?! Wolvesbane...? You can make an exact copy of that too?","TWN":"啊？！狼之災禍……？你竟然能完美地複製它？"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_QM","text":{"KOREA":"거울은 너의 내면을 비추고, 클리파 차원은 그 내면을 실체화시킬 힘이 있어.","JPN":"鏡はあなたの内面を映し、クリファ次元はその内面を実体化させる力を持っている。","ENG":"The mirror reflects your inner self, and the Qlipha Dimension has the power to materialize it.","TWN":"鏡子會照出你的內心，而逆卡巴拉次元的力量可以將其實體化。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_QM","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_QM","text":{"KOREA":"난 너야. 정확히는 과거의 너지.","JPN":"私はあなただ。正確に言えば過去のあなたね。","ENG":"I'm you. To be exact, I'm the past you.","TWN":"我就是你，或者更準確地說，是過去的你。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_QM","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"알겠으니까 설명 다 했으면 비켜.","JPN":"わかったから、説明が終わったのならそこをどけ。","ENG":"All right. If you're done talking, get out of my way.","TWN":"好了，你說完了吧？快讓路吧。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_QM","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"난 과거 따위랑 씨름할 여유 없으니까.","JPN":"私は過去と遊んでいる暇はない。","ENG":"I don't have time to fight with the past.","TWN":"我沒有時間與過去的我糾纏。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_QM","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_QM","text":{"KOREA":"그렇게는 안돼. 네가 나아가려 한다면, 나도 나아가는 것이 이 거울의 규칙.","JPN":"それはできない。あなたが進もうとするなら、私も進むことがこの鏡のルール。","ENG":"I can't do that. If you try to move forward, then I do too. That's the mirror's rule.","TWN":"那可不行。這面鏡子的規則是，如果你繼續前進，我也會繼續前進。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_QM","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_QM","text":{"KOREA":"하지만 지금의 넌 날 이길 수 없어. 나보다 약하니까.","JPN":"でも今のあなたは私に勝てない。私より弱いから。","ENG":"Also, the current you can't beat me. Because you're weaker.","TWN":"但現在的你還打不過我，因為你比我弱。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_QM","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"내가… 예전보다 약하다고?","JPN":"私が……昔より弱いだと？","ENG":"I'm... weaker than my old self?","TWN":"我……比以前更弱了？"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_QM","text":{"KOREA":"지금껏 나 자신을 위해, 신념을 위해, 가족을 위해서 싸운다고 생각했지.","JPN":"今まで自分のため、信念のため、家族のために戦っているつもりだったでしょう。","ENG":"Until now, you thought you were fighting for yourself, your beliefs, and your family.","TWN":"我以為我一直以來都是為自己、為信念、為家人而戰。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_QM","text":{"KOREA":"그런데 막상 뒤돌아보니 네가 지켜야 할 건 아무것도 없었잖아?","JPN":"でも、いざ振り返ってみるとあなたが守るべきものは何もなかったよね？","ENG":"But looking back, there's nothing for you to protect.","TWN":"但回過頭來看，其實你並沒有什麼需要保護的，對嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_QM","text":{"KOREA":"나약해지는 거야. 싸워야 할 이유를 잃었으니까.","JPN":"あなたは軟弱になるんだ。戦う理由を失ったから。","ENG":"You're weak. Because you lost your reason to fight.","TWN":"所以你變軟弱了。因為你失去了戰鬥的理由。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그래, 그래. 무슨 말하는지 알겠는데…","JPN":"あ、そう。言いたいことはわかるけど……","ENG":"Okay, okay. I get what you're saying, but...","TWN":"是啊，是啊。我明白你的意思，但是……"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"관심 없으니 비키라고.","JPN":"興味ないから、そこどけよ。","ENG":"I'm not interested, so get out of my way.","TWN":"我沒興趣，別擋我的路。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};